import{_ as a,c as e,o,a1 as r}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"릴리스 노트: 버전 변경 이력 | Antigravity-Manager","description":"Antigravity-Manager의 버전 변경 이력 방법을 이해합니다. Settings 페이지에서 버전을 확인하고 업데이트를 검사하며, README Changelog를 통해 수정 사항 및 알림을 보고 /healthz로 업그레이드 후 가용성을 검증합니다.","frontmatter":{"title":"릴리스 노트: 버전 변경 이력 | Antigravity-Manager","sidebarTitle":"3분 만에 버전 업데이트 이해","subtitle":"버전 변경 이력: README 내장 Changelog 기준","description":"Antigravity-Manager의 버전 변경 이력 방법을 이해합니다. Settings 페이지에서 버전을 확인하고 업데이트를 검사하며, README Changelog를 통해 수정 사항 및 알림을 보고 /healthz로 업그레이드 후 가용성을 검증합니다.","tags":["changelog","release","upgrade","troubleshooting"],"prerequisite":["start-installation","start-proxy-and-first-client"],"order":1},"headers":[],"relativePath":"ko/lbjlaq/Antigravity-Manager/changelog/release-notes/index.md","filePath":"ko/lbjlaq/Antigravity-Manager/changelog/release-notes/index.md"}'),l={name:"ko/lbjlaq/Antigravity-Manager/changelog/release-notes/index.md"};function n(i,t,d,s,g,h){return o(),e("div",null,[...t[0]||(t[0]=[r('<h1 id="버전-변경-이력-readme-내장-changelog-기준" tabindex="-1">버전 변경 이력: README 내장 Changelog 기준 <a class="header-anchor" href="#버전-변경-이력-readme-내장-changelog-기준" aria-label="Permalink to &quot;버전 변경 이력: README 내장 Changelog 기준&quot;">​</a></h1><p>Antigravity Tools를 업그레이드할 준비를 할 때 가장 두려운 것은 &quot;업데이트되지 않음&quot;이 아니라 &quot;업데이트 후 호환성 변경을 발견&quot;하는 것입니다. 이 페이지는 **Antigravity Tools Changelog(버전 변경 이력)**의 읽는 방법을 명확히 설명하여 업그레이드 전에 이번 업데이트가 무엇에 영향을 미치는지 판단할 수 있게 해줍니다.</p><h2 id="학습-후-가능한-작업" tabindex="-1">학습 후 가능한 작업 <a class="header-anchor" href="#학습-후-가능한-작업" aria-label="Permalink to &quot;학습 후 가능한 작업&quot;">​</a></h2><ul><li>Settings의 About 페이지에서 현재 버전을 빠르게 확인하고, 업데이트를 검사하여 다운로드 진입점 획득</li><li>README의 Changelog에서 자신에게 영향을 미치는 버전 구간만 읽기 (처음부터 끝까지 읽지 않음)</li><li>업그레이드 전 한 가지 작업 수행: &quot;구성/모델 매핑 수동 수정&quot; 알림이 있는지 확인</li><li>업그레이드 후 최소 검증(<code>/healthz</code>) 한 번 실행하여 프록시 사용 가능 여부 확인</li></ul><h2 id="changelog란" tabindex="-1">Changelog란? <a class="header-anchor" href="#changelog란" aria-label="Permalink to &quot;Changelog란?&quot;">​</a></h2><p><strong>Changelog</strong>는 버전별로 &quot;이번에 무엇이 변경되었는지&quot;를 기록한 목록입니다. Antigravity Tools는 이를 README의 &quot;버전 변경 이력&quot;에 직접 작성하며, 각 버전마다 날짜와 핵심 변경 사항을 표시합니다. 업그레이드 전 Changelog를 확인하면 호환성 변경 또는 회귀 문제에 빠질 확률이 줄어듭니다.</p><h2 id="이-페이지를-사용하는-경우" tabindex="-1">이 페이지를 사용하는 경우 <a class="header-anchor" href="#이-페이지를-사용하는-경우" aria-label="Permalink to &quot;이 페이지를 사용하는 경우&quot;">​</a></h2><ul><li>이전 버전에서 새 버전으로 업그레이드할 준비 중, 먼저 위험 지점을 확인하고 싶을 때</li><li>특정 문제(예: 429/0 Token/Cloudflared)를 만나서 최근 버전에서 수정되었는지 확인하고 싶을 때</li><li>팀에서 통합 버전을 유지하며 동료에게 &quot;버전별 변경 사항 읽는 방법&quot;을 제공해야 할 때</li></ul><h2 id="🎒-시작-전-준비" tabindex="-1">🎒 시작 전 준비 <a class="header-anchor" href="#🎒-시작-전-준비" aria-label="Permalink to &quot;🎒 시작 전 준비&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">업그레이드 경로 먼저 준비 권장</p><p>설치/업그레이드 방법이 많습니다 (brew, Releases 수동 다운로드, 앱 내 업데이트). 아직 어떤 경로를 사용할지 결정하지 않았다면 먼저 **<a href="/docs/opencodedocs/ko/lbjlaq/Antigravity-Manager/start/installation/">설치 및 업그레이드: 데스크톱용 최적 설치 경로(brew / releases)</a>**를 보세요.</p></div><h2 id="같이-해보기" tabindex="-1">같이 해보기 <a class="header-anchor" href="#같이-해보기" aria-label="Permalink to &quot;같이 해보기&quot;">​</a></h2><h3 id="_1단계-about-페이지에서-현재-사용-중인-버전-확인" tabindex="-1">1단계: About 페이지에서 현재 사용 중인 버전 확인 <a class="header-anchor" href="#_1단계-about-페이지에서-현재-사용-중인-버전-확인" aria-label="Permalink to &quot;1단계: About 페이지에서 현재 사용 중인 버전 확인&quot;">​</a></h3><p><strong>왜인가요</strong> Changelog는 버전별로 구성되어 있습니다. 현재 버전을 먼저 알아야 &quot;어디서부터 읽어야 하는지&quot; 알 수 있습니다.</p><p>조작 경로: <strong>Settings</strong> → <strong>About</strong>.</p><p><strong>다음을 볼 수 있어야 함</strong>: 페이지 제목 영역에 애플리케이션 이름 및 버전 번호가 표시됩니다 (예: <code>v3.3.49</code>).</p><h3 id="_2단계-업데이트-검사-클릭-최신-버전-및-다운로드-진입점-획득" tabindex="-1">2단계: &quot;업데이트 검사&quot; 클릭, 최신 버전 및 다운로드 진입점 획득 <a class="header-anchor" href="#_2단계-업데이트-검사-클릭-최신-버전-및-다운로드-진입점-획득" aria-label="Permalink to &quot;2단계: &quot;업데이트 검사&quot; 클릭, 최신 버전 및 다운로드 진입점 획득&quot;">​</a></h3><p><strong>왜인가요</strong> &quot;최신 버전 번호&quot;를 먼저 알아야 Changelog에서 중간에 건너뛴 버전 구간을 선택할 수 있습니다.</p><p>About 페이지에서 &quot;업데이트 검사&quot; 클릭.</p><p><strong>다음을 볼 수 있어야 함</strong>:</p><ul><li>업데이트가 있는 경우: &quot;new version available&quot; 메시지와 다운로드 버튼이 표시됨 (<code>download_url</code> 열림)</li><li>이미 최신 버전인 경우: &quot;latest version&quot; 메시지</li></ul><h3 id="_3단계-readme의-changelog에서-건너뛴-버전만-보기" tabindex="-1">3단계: README의 Changelog에서 건너뛴 버전만 보기 <a class="header-anchor" href="#_3단계-readme의-changelog에서-건너뛴-버전만-보기" aria-label="Permalink to &quot;3단계: README의 Changelog에서 건너뛴 버전만 보기&quot;">​</a></h3><p><strong>왜인가요</strong> &quot;현재 버전에서 최신 버전까지&quot;의 변경 사항만 관심을 가지면 되며, 다른 과거 버전은 일단 건너뛸 수 있습니다.</p><p>README를 열고 **&quot;버전 변경 이력(Changelog)&quot;**으로 이동한 다음 최신 버전부터 내려가서 현재 버전까지 읽습니다.</p><p><strong>다음을 볼 수 있어야 함</strong>: 버전이 <code>vX.Y.Z (YYYY-MM-DD)</code> 형식으로 나열되며, 각 버전마다 그룹 설명(예: 핵심 수정/기능 향상)이 있습니다.</p><h3 id="_4단계-업그레이드-후-최소-검증-한-번-수행" tabindex="-1">4단계: 업그레이드 후 최소 검증 한 번 수행 <a class="header-anchor" href="#_4단계-업그레이드-후-최소-검증-한-번-수행" aria-label="Permalink to &quot;4단계: 업그레이드 후 최소 검증 한 번 수행&quot;">​</a></h3><p><strong>왜인가요</strong> 업그레이드 후 첫 번째 작업은 &quot;복잡한 시나리오 실행&quot;이 아니라 프록시가 정상적으로 시작되고 클라이언트에서 활성화되는지 먼저 확인하는 것입니다.</p><p>**<a href="/docs/opencodedocs/ko/lbjlaq/Antigravity-Manager/start/proxy-and-first-client/">로컬 리버스 프록시 시작 및 첫 번째 클라이언트 연결(/healthz + SDK 구성)</a>**의 흐름에 따라 최소한 한 번 <code>GET /healthz</code>를 검증합니다.</p><p><strong>다음을 볼 수 있어야 함</strong>: <code>/healthz</code>가 성공을 반환 (서비스 가용성 확인용).</p><h2 id="최근-버전-요약-readme에서-발췌" tabindex="-1">최근 버전 요약 (README에서 발췌) <a class="header-anchor" href="#최근-버전-요약-readme에서-발췌" aria-label="Permalink to &quot;최근 버전 요약 (README에서 발췌)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>버전</th><th>날짜</th><th>주의해야 할 점</th></tr></thead><tbody><tr><td><code>v3.3.49</code></td><td>2026-01-22</td><td>Thinking 중단 및 0 Token 방어; <code>gemini-2.5-flash-lite</code> 제거 및 사용자 정의 매핑 수동 교체 알림; 언어/테마 등 설정 즉시 적용; 모니터링 대시보드 강화; OAuth 호환성 향상</td></tr><tr><td><code>v3.3.48</code></td><td>2026-01-21</td><td>Windows 플랫폼 백그라운드 프로세스 무음 실행 (콘솔 깜빡임 수정)</td></tr><tr><td><code>v3.3.47</code></td><td>2026-01-21</td><td>이미지 생성 파라미터 매핑 강화(<code>size</code>/<code>quality</code>); Cloudflared 터널 지원; 병합 충돌로 인한 시작 실패 수정; 3단계 점진적 컨텍스트 압축</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">&quot;이번 업데이트가 나에게 영향을 미치는지&quot; 빠르게 판단하는 방법</p><p>다음 두 가지 유형의 문장을 우선 찾으세요:</p><ul><li><strong>사용자 알림/사용자 수정 필요</strong>: 예를 들어 특정 기본 모델이 제거되어 사용자 정의 매핑을 수동으로 조정해야 한다는 명시</li><li><strong>핵심 수정/호환성 수정</strong>: 예를 들어 0 Token, 429, Windows 깜빡임, 시작 실패 같은 &quot;사용 불가능하게 만드는&quot; 문제</li></ul></div><hr><h2 id="부록-소스코드-참조" tabindex="-1">부록: 소스코드 참조 <a class="header-anchor" href="#부록-소스코드-참조" aria-label="Permalink to &quot;부록: 소스코드 참조&quot;">​</a></h2><details><summary><strong>클릭하여 소스코드 위치 확인</strong></summary><blockquote><p>업데이트 시간: 2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>내용</th><th>파일 경로</th><th>행 번호</th></tr></thead><tbody><tr><td>README 내장 Changelog(버전 변경 이력)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/README.md#L324-L455" target="_blank" rel="noreferrer"><code>README.md</code></a></td><td>324-455</td></tr><tr><td>About 페이지 버전 번호 표시 및 &quot;업데이트 검사&quot; 버튼</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/pages/Settings.tsx#L821-L954" target="_blank" rel="noreferrer"><code>src/pages/Settings.tsx</code></a></td><td>821-954</td></tr><tr><td>About 페이지 &quot;업데이트 검사&quot; 명령 반환 구조</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/pages/Settings.tsx#L187-L215" target="_blank" rel="noreferrer"><code>src/pages/Settings.tsx</code></a></td><td>187-215</td></tr><tr><td>자동 업데이트 알림(다운로드 및 재시작)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/components/UpdateNotification.tsx#L33-L96" target="_blank" rel="noreferrer"><code>src/components/UpdateNotification.tsx</code></a></td><td>33-96</td></tr><tr><td>현재 버전 번호(빌드 메타데이터)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/package.json#L1-L4" target="_blank" rel="noreferrer"><code>package.json</code></a></td><td>1-4</td></tr></tbody></table></details>',34)])])}const b=a(l,[["render",n]]);export{u as __pageData,b as default};
